import React, { useEffect, useState, useMemo, useRef } from 'https://cdn.jsdelivr.net/npm/react@18.2.0/+esm';
import ReactDOM from 'https://cdn.jsdelivr.net/npm/react-dom@18.2.0/+esm';

const TEXT_MAIN = '#1f2937';
const TEXT_SUB = '#64748b';
const D_COLOR = '#BFE0EF';

function IZOBubbleChart(props) {
  const [isLoaded, setIsLoaded] = useState(false);
  const [tooltip, setTooltip] = useState({ show: false, x: 0, y: 0, name: "", value: 0 });
  const containerRef = useRef(null);

  useEffect(() => {
    const styleId = 'izo-header-sync-styles';
    if (!document.getElementById(styleId)) {
      const style = document.createElement('style');
      style.id = styleId;
      style.innerHTML = `
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');
        html, body { margin: 0; padding: 0; font-family: 'Inter', sans-serif; background: white; overflow: hidden; }
        .chart-header-title { font-size: 16px; font-weight: 600; color: #374151; margin: 0; }
        .chart-header-sub { font-size: 14px; font-weight: 400; color: #6b7280; margin: 0; }
        .bubble-group { cursor: pointer; transition: transform 0.3s ease; }
        .bubble-group:hover { transform: scale(1.02); }
        .bubble-text { text-anchor: middle; dominant-baseline: central; pointer-events: none; }
        .izo-tooltip {
          position: fixed; background: #111827; color: #ffffff; border-radius: 4px;
          padding: 6px 10px; pointer-events: none; z-index: 9999; font-size: 11px;
        }
      `;
      document.head.appendChild(style);
    }
    setIsLoaded(true);
  }, []);

  const bubbles = useMemo(() => {
    const raw = props.data || {};
    const inputData = Array.isArray(raw.data) ? raw.data : [];
    const baseColor = raw.color || D_COLOR;
    const midColor = baseColor + 'B2';
    const lowColor = baseColor + '80';
    const maxValue = Math.max(...inputData.map(d => d.value || 0), 1);

    const getRadius = (val) => {
      const minR = 32; 
      const maxR = 80; 
      const normalized = Math.sqrt(val / maxValue); 
      return Math.max(minR, normalized * maxR);
    };

    let computed = [
      { x: 150, y: 130, color: baseColor }, // ✅ Y-coordinates shifted up to reduce gap
      { x: 300, y: 140, color: midColor }, 
      { x: 440, y: 100, color: midColor }, 
      { x: 560, y: 110, color: midColor }, 
      { x: 570, y: 220, color: midColor }, 
      { x: 450, y: 240, color: lowColor }  
    ].map((config, i) => {
      const dataItem = inputData[i] || {};
      const val = dataItem.value || 0;
      const r = getRadius(val);

      const titleSize = Math.max(10, Math.min(15, (r / 80) * 15));
      const countSize = Math.max(8.5, Math.min(11, (r / 80) * 11));
      const BASE_GAP = 4;
      const dynamicGap = Math.max(BASE_GAP, (r / 80) * 10); 

      const titleDy = -(dynamicGap / 2);
      const countDy = (dynamicGap / 2) + (countSize / 1.2);

      return {
        ...config,
        r,
        fullName: dataItem.name || "",
        displayName: dataItem.name || "",
        titleSize,
        countSize,
        titleDy,
        countDy,
        value: val
      };
    });

    const padding = 22; 
    for (let iter = 0; iter < 100; iter++) {
      for (let i = 0; i < computed.length; i++) {
        for (let j = i + 1; j < computed.length; j++) {
          const b1 = computed[i];
          const b2 = computed[j];
          const dx = b2.x - b1.x;
          const dy = b2.y - b1.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          const minDist = b1.r + b2.r + padding;
          if (dist < minDist) {
            const angle = Math.atan2(dy, dx);
            const force = (minDist - dist) / 2;
            b1.x -= Math.cos(angle) * force;
            b1.y -= Math.sin(angle) * force;
            b2.x += Math.cos(angle) * force;
            b2.y += Math.sin(angle) * force;
          }
        }
      }
    }
    return computed;
  }, [props.data]);

  return React.createElement(
    'div',
    { className: "flex flex-col h-full w-full bg-white overflow-hidden", ref: containerRef },

    tooltip.show && React.createElement('div', {
      className: "izo-tooltip",
      style: { left: tooltip.x, top: tooltip.y }
    },
      React.createElement('div', { style: { fontWeight: 700 } }, tooltip.name),
      React.createElement('div', null, `${tooltip.value}`)
    ),

    // ✅ Header marginBottom reduced from 4px to 0px
    React.createElement('div', { style: { padding: '36px 36px 0px 36px' } },
      React.createElement('h3', { className: "chart-header-title" }, props.data?.title || "Recent Themes"),
      React.createElement('p', { className: "chart-header-sub", style: { marginTop: '8px' } }, props.data?.subtitle || "Tracking scientific queries.")
    ),

    React.createElement(
      'svg',
      {
        viewBox: "0 0 750 360", // ✅ Height reduced to clip excess bottom space
        className: "w-full h-full flex-1",
        onMouseLeave: () => setTooltip({ ...tooltip, show: false }),
        style: { marginTop: '-10px' } // ✅ Negative margin to pull SVG closer to subtitle
      },

      bubbles.map((item, i) => (
        React.createElement(
          'g',
          {
            key: i,
            className: "bubble-group",
            onMouseMove: (e) => setTooltip({ show: true, x: e.clientX + 10, y: e.clientY - 30, name: item.fullName, value: item.value }),
            onMouseLeave: () => setTooltip({ ...tooltip, show: false })
          },

          React.createElement('circle', { cx: item.x, cy: item.y, r: item.r, fill: item.color }),

          React.createElement('text', {
            x: item.x, y: item.y, dy: `${item.titleDy}px`,
            className: "bubble-text",
            style: { fontSize: `${item.titleSize}px`, fontWeight: 700, fill: TEXT_MAIN }
          }, item.displayName),

          React.createElement('text', {
            x: item.x, y: item.y, dy: `${item.countDy}px`,
            className: "bubble-text",
            style: { fontSize: `${item.countSize}px`, fontWeight: 500, fill: TEXT_SUB }
          }, `${item.value} Mentions`)
        )
      ))
    )
  );
}

const ConnectedComponent = Tooljet.connectComponent(IZOBubbleChart);
if (!window.tooljetRoot) window.tooljetRoot = ReactDOM.createRoot(document.body);
window.tooljetRoot.render(React.createElement(ConnectedComponent));
